def _populate_s3_object_attrs(attrs: S3ObjectAttributes, obj: S3Object) -> None:
    """Populate S3Object-specific attributes on the attrs struct."""
    _populate_asset_attrs(attrs, obj)
    attrs.s3_object_last_modified_time = obj.s3_object_last_modified_time
    attrs.s3_bucket_name = obj.s3_bucket_name
    attrs.s3_bucket_qualified_name = obj.s3_bucket_qualified_name
    attrs.s3_object_size = obj.s3_object_size
    attrs.s3_object_storage_class = obj.s3_object_storage_class
    attrs.s3_object_key = obj.s3_object_key
    attrs.s3_object_content_type = obj.s3_object_content_type
    attrs.s3_object_content_disposition = obj.s3_object_content_disposition
    attrs.s3_object_version_id = obj.s3_object_version_id
    attrs.s3_object_lock_retain_until = obj.s3_object_lock_retain_until
    attrs.s3_object_lock_mode = obj.s3_object_lock_mode
    attrs.s3_object_lock_legal_hold_enabled = obj.s3_object_lock_legal_hold_enabled
    attrs.s3_etag = obj.s3_etag
    attrs.s3_encryption = obj.s3_encryption
    attrs.s3_parent_prefix_qualified_name = obj.s3_parent_prefix_qualified_name
    attrs.s3_prefix_hierarchy = obj.s3_prefix_hierarchy
    attrs.aws_arn = obj.aws_arn
    attrs.aws_partition = obj.aws_partition
    attrs.aws_service = obj.aws_service
    attrs.aws_region = obj.aws_region
    attrs.aws_account_id = obj.aws_account_id
    attrs.aws_resource_id = obj.aws_resource_id
    attrs.aws_owner_name = obj.aws_owner_name
    attrs.aws_owner_id = obj.aws_owner_id
    attrs.aws_tags = obj.aws_tags
    attrs.cloud_uniform_resource_name = obj.cloud_uniform_resource_name


def _extract_s3_object_attrs(attrs: S3ObjectAttributes) -> dict:
    """Extract all S3Object attributes from the attrs struct into a flat dict."""
    result = _extract_asset_attrs(attrs)
    result["s3_object_last_modified_time"] = attrs.s3_object_last_modified_time
    result["s3_bucket_name"] = attrs.s3_bucket_name
    result["s3_bucket_qualified_name"] = attrs.s3_bucket_qualified_name
    result["s3_object_size"] = attrs.s3_object_size
    result["s3_object_storage_class"] = attrs.s3_object_storage_class
    result["s3_object_key"] = attrs.s3_object_key
    result["s3_object_content_type"] = attrs.s3_object_content_type
    result["s3_object_content_disposition"] = attrs.s3_object_content_disposition
    result["s3_object_version_id"] = attrs.s3_object_version_id
    result["s3_object_lock_retain_until"] = attrs.s3_object_lock_retain_until
    result["s3_object_lock_mode"] = attrs.s3_object_lock_mode
    result["s3_object_lock_legal_hold_enabled"] = (
        attrs.s3_object_lock_legal_hold_enabled
    )
    result["s3_etag"] = attrs.s3_etag
    result["s3_encryption"] = attrs.s3_encryption
    result["s3_parent_prefix_qualified_name"] = attrs.s3_parent_prefix_qualified_name
    result["s3_prefix_hierarchy"] = attrs.s3_prefix_hierarchy
    result["aws_arn"] = attrs.aws_arn
    result["aws_partition"] = attrs.aws_partition
    result["aws_service"] = attrs.aws_service
    result["aws_region"] = attrs.aws_region
    result["aws_account_id"] = attrs.aws_account_id
    result["aws_resource_id"] = attrs.aws_resource_id
    result["aws_owner_name"] = attrs.aws_owner_name
    result["aws_owner_id"] = attrs.aws_owner_id
    result["aws_tags"] = attrs.aws_tags
    result["cloud_uniform_resource_name"] = attrs.cloud_uniform_resource_name
    return result


